Implement `CheckBattleEnd()`:
```cpp
void ALFPTurnManager::CheckBattleEnd()
{
    if (bBattleEnded) return;
    if (CurrentPhase == EBattlePhase::BP_Deployment) return; // 布置阶段不检查

    bool bHasPlayerUnit = false;
    bool bHasEnemyUnit = false;

    for (ALFPTacticsUnit* Unit : TurnOrderUnits)
    {
        if (!Unit || !Unit->IsAlive()) continue;

        if (Unit->GetAffiliation() == EUnitAffiliation::UA_Player)
            bHasPlayerUnit = true;
        else if (Unit->GetAffiliation() == EUnitAffiliation::UA_Enemy)
            bHasEnemyUnit = true;
    }

    if (!bHasEnemyUnit)
    {
        // 胜利
        bBattleEnded = true;
        if (ALFPTurnGameMode* GM = Cast<ALFPTurnGameMode>(GetWorld()->GetAuthGameMode()))
        {
            GM->EndBattle(true);
        }
    }
    else if (!bHasPlayerUnit)
    {
        // 失败
        bBattleEnded = true;
        if (ALFPTurnGameMode* GM = Cast<ALFPTurnGameMode>(GetWorld()->GetAuthGameMode()))
        {
            GM->EndBattle(false);
        }
    }
}
```

**Key detail**: `CheckBattleEnd()` is called from `UnregisterUnit()`, which is called from `HandleDeath()`, which has a 2-second delayed Destroy. So at the point of checking, the unit is already removed from TurnOrderUnits but not yet destroyed. The `OnEnemyUnitKilled` in TurnGameMode should be called BEFORE `UnregisterUnit` (it is -- `HandleDeath` order is: OnDeathDelegate broadcast, then OnDeath BP event, then tile cleanup, then UnregisterUnit). So we need to add the `OnEnemyUnitKilled` call before the `UnregisterUnit` call in `HandleDeath()`.

Revised order in `HandleDeath()`:
```cpp
void ALFPTacticsUnit::HandleDeath()
{
    bIsDead = true;
    OnDeathDelegate.Broadcast();
    OnDeath(); // Blueprint event

    // 通知 GameMode 敌方单位被击杀（掉落追踪）
    if (IsEnemy())
    {
        if (ALFPTurnGameMode* GM = Cast<ALFPTurnGameMode>(GetWorld()->GetAuthGameMode()))
        {
            GM->OnEnemyUnitKilled(this);
        }
    }

    // 从格子上移除
    ALFPHexTile* CurrentTile = GetCurrentTile();
    if (CurrentTile) { ... }

    // 从回合系统中移除 (this triggers CheckBattleEnd)
    if (ALFPTurnManager* TurnManager = GetTurnManager())
    {
        TurnManager->UnregisterUnit(this);
    }
    // ... rest unchanged
}
```

