 81→void ALFPWorldMapGameMode::HandleBattleResult(const FLFPBattleResult& Result)
 82→{
 83→	if (!WorldMapManager) return;
 84→
 85→	UE_LOG(LogTemp, Log, TEXT("处理战斗结果: 节点 %d, 胜利=%s, 逃跑=%s"),
 86→		Result.SourceNodeID,
 87→		Result.bVictory ? TEXT("是") : TEXT("否"),
 88→		Result.bEscaped ? TEXT("是") : TEXT("否"));
 89→
 90→	if (Result.bVictory)
 91→	{
 92→		// 胜利：节点标记为已触发（如果尚未标记）
 93→		ALFPWorldMapNode* Node = WorldMapManager->GetNode(Result.SourceNodeID);
 94→		if (Node && !Node->bHasBeenTriggered)
 95→		{
 96→			Node->bHasBeenTriggered = true;
 97→			Node->UpdateVisualState();
 98→		}
 99→
100→		// 处理捕获的单位
101→		if (Result.CapturedUnits.Num() > 0)
102→		{
103→			ProcessCapturedUnits(Result.CapturedUnits);
104→		}
105→	}
106→	else if (Result.bEscaped)
107→	{
108→		// 逃跑：不标记为已触发，可再次进入
109→		UE_LOG(LogTemp, Log, TEXT("逃跑：节点 %d 未标记为已触发"), Result.SourceNodeID);
110→	}
111→	else
112→	{
113→		// 失败：根据游戏设计决定处理方式
114→		// TODO: 游戏结束 or 惩罚后继续
115→		UE_LOG(LogTemp, Warning, TEXT("战斗失败：节点 %d"), Result.SourceNodeID);
116→	}
117→}
118→
119→void ALFPWorldMapGameMode::ProcessCapturedUnits(const TArray<FLFPUnitEntry>& CapturedUnits)
120→{
121→	ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance());
122→	if (!GI) return;
123→
124→	for (const FLFPUnitEntry& Unit : CapturedUnits)
125→	{
126→		if (!GI->TryAddUnit(Unit))
127→		{
128→			// 队伍和备战营都满了，加入待处理队列
129→			PendingCapturedUnits.Add(Unit);
130→		}
131→	}
132→
133→	// 有待处理的，显示替换 UI
134→	if (PendingCapturedUnits.Num() > 0)
135→	{
136→		ShowNextReplacementUI();
137→	}
138→}
139→
140→void ALFPWorldMapGameMode::ShowNextReplacementUI()
141→{
142→	if (PendingCapturedUnits.Num() == 0) return;
143→
144→	FLFPUnitEntry NextUnit = PendingCapturedUnits[0];
145→	PendingCapturedUnits.RemoveAt(0);
146→
147→	if (!ReplacementWidgetClass)
148→	{
149→		UE_LOG(LogTemp, Warning, TEXT("ReplacementWidgetClass 未配置，放弃单位 %s"), *NextUnit.TypeID.ToString());
150→		ShowNextReplacementUI();
151→		return;
152→	}
153→
154→	ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance());
155→	if (!GI) return;
156→
157→	APlayerController* PC = GetWorld()->GetFirstPlayerController();
158→	if (!PC) return;
159→
160→	if (!ReplacementWidget)
161→	{
162→		ReplacementWidget = CreateWidget<ULFPUnitReplacementWidget>(PC, ReplacementWidgetClass);
163→	}
164→
165→	if (ReplacementWidget)
166→	{
167→		ReplacementWidget->Setup(NextUnit, GI->PartyUnits, GI->ReserveUnits, GI->UnitRegistry);
168→		ReplacementWidget->OnReplacementComplete.AddDynamic(this, &ALFPWorldMapGameMode::OnReplacementComplete);
169→		ReplacementWidget->AddToViewport(100);
170→	}
171→}
172→
173→void ALFPWorldMapGameMode::OnReplacementComplete()
174→{
175→	if (ReplacementWidget)
176→	{
177→		ReplacementWidget->RemoveFromParent();
178→		ReplacementWidget->OnReplacementComplete.RemoveDynamic(this, &ALFPWorldMapGameMode::OnReplacementComplete);
179→	}
180→
181→	// 处理下一个
182→	ShowNextReplacementUI();
183→}
