 58→void ALFPTurnManager::EndDeploymentPhase()
 59→{
 60→    UE_LOG(LogTemp, Log, TEXT("布置阶段结束，注册玩家单位"));
 61→
 62→    // 收集布置阶段放置的玩家单位
 63→    TArray<AActor*> FoundActors;
 64→    UGameplayStatics::GetAllActorsOfClass(GetWorld(), ALFPTacticsUnit::StaticClass(), FoundActors);
 65→
 66→    for (AActor* Actor : FoundActors)
 67→    {
 68→        if (ALFPTacticsUnit* Unit = Cast<ALFPTacticsUnit>(Actor))
 69→        {
 70→            if (Unit->GetAffiliation() == EUnitAffiliation::UA_Player && !TurnOrderUnits.Contains(Unit))
 71→            {
