119→    // 通知玩家本回合结束
120→    for (FConstPlayerControllerIterator It = GetWorld()->GetPlayerControllerIterator(); It; ++It)
121→    {
122→        if (ALFPTacticsPlayerController* PC = Cast<ALFPTacticsPlayerController>(*It))
123→        {
124→            PC->OnRoundEnded(CurrentRound);
125→        }
126→    }
127→
128→    // 添加延迟后开始新回合
129→    FTimerHandle TimerHandle;
130→    GetWorld()->GetTimerManager().SetTimer(TimerHandle, this, &ALFPTurnManager::BeginNewRound, 0.5f, false);
131→}
