133→void ALFPTurnManager::SortUnitsBySpeed()
134→{
135→    // 按速度降序排序（速度高的先行动）
136→    // Todo: 速度相同时随机排序（玩家优先于AI）
137→    TurnOrderUnits.Sort([](const ALFPTacticsUnit& A, const ALFPTacticsUnit& B) {
138→        return A.GetSpeed() > B.GetSpeed();
139→        });
140→}
141→
142→// ==== 阶段管理 ====
143→
144→void ALFPTurnManager::SetPhase(EBattlePhase NewPhase)
145→{
146→    CurrentPhase = NewPhase;
147→    UE_LOG(LogTemp, Log, TEXT("SetPhase:=%d"), NewPhase);
148→    OnPhaseChanged.Broadcast(NewPhase);
149→}
150→
151→// ==== 敌人规划阶段 ====
152→
153→void ALFPTurnManager::BeginEnemyPlanningPhase()
154→{
155→    SetPhase(EBattlePhase::BP_EnemyPlanning);
156→
157→    // 过滤出存活的敌方单位，按速度排序
158→    PlanningOrderEnemies.Empty();
159→    for (ALFPTacticsUnit* Unit : TurnOrderUnits)
160→    {
161→        if (Unit && Unit->IsAlive() && Unit->IsEnemy())
162→        {
163→            PlanningOrderEnemies.Add(Unit);
164→        }
165→    }
166→
167→    // 敌方单位已按速度排序（继承自 TurnOrderUnits 的排序）
168→
169→    CurrentPlanningEnemyIndex = 0;
170→
171→    if (PlanningOrderEnemies.Num() == 0)
172→    {
173→        // 没有敌方单位，直接进入行动阶段
174→        EndEnemyPlanningPhase();
175→        return;
176→    }
177→
178→    // 隐藏玩家技能选择UI
179→    if (ALFPTacticsPlayerController* PC = GetWorld()->GetFirstPlayerController<ALFPTacticsPlayerController>())
180→    {
181→        PC->HideSkillSelection();
182→    }
183→
184→    // Step 1: 全局技能分配（按优先级分配AP技能）
185→    AllocateEnemySkills();
186→
187→    // Step 2: 按速度顺序移动展示
188→    ProcessNextEnemyPlan();
189→}
190→
191→void ALFPTurnManager::ProcessNextEnemyPlan()
192→{
193→    if (CurrentPlanningEnemyIndex >= PlanningOrderEnemies.Num())
194→    {
195→        // 所有敌人规划完毕
196→        EndEnemyPlanningPhase();
197→        return;
198→    }
199→
200→    ALFPTacticsUnit* Enemy = PlanningOrderEnemies[CurrentPlanningEnemyIndex];
201→
202→    // 跳过死亡单位
203→    if (!Enemy || !Enemy->IsAlive())
204→    {
205→        CurrentPlanningEnemyIndex++;
206→        ProcessNextEnemyPlan();
207→        return;
208→    }
209→
210→    ALFPAIController* AIController = Enemy->GetAIController();
211→    if (!AIController)
212→    {
213→        CurrentPlanningEnemyIndex++;
214→        ProcessNextEnemyPlan();
215→        return;
216→    }
217→
218→    // 创建行动计划，传入预分配的技能
219→    ULFPSkillBase* PreAllocatedSkill = nullptr;
220→    if (ULFPSkillBase** Found = AllocatedSkills.Find(Enemy))
221→    {
222→        PreAllocatedSkill = *Found;
223→    }
224→    FEnemyActionPlan Plan = AIController->CreateActionPlan(PreAllocatedSkill);
225→
226→    // 存储计划
227→    EnemyActionPlans.Add(Plan);
228→    Enemy->SetActionPlan(Plan);
229→
230→    // 推进到下一个敌人，加延时让玩家观察
231→    CurrentPlanningEnemyIndex++;
232→    FTimerHandle TimerHandle;
233→    GetWorld()->GetTimerManager().SetTimer(
234→        TimerHandle,
235→        this,
236→        &ALFPTurnManager::ProcessNextEnemyPlan,
237→        0.5f,
238→        false
239→    );
240→}
241→
242→void ALFPTurnManager::EndEnemyPlanningPhase()
243→{
244→    BeginActionPhase();
245→}
246→
247→// ==== 行动阶段 ====
248→
249→void ALFPTurnManager::BeginActionPhase()
250→{
251→    SetPhase(EBattlePhase::BP_ActionPhase);
252→
253→    // 开始第一个单位的回合
254→    if (TurnOrderUnits.Num() > 0)
255→    {
256→        BeginUnitTurn(TurnOrderUnits[0]);
257→    }
258→}
259→
260→void ALFPTurnManager::BeginUnitTurn(ALFPTacticsUnit* Unit)
261→{
262→    OnTurnChanged.Broadcast();
263→
264→    CurrentUnit = Unit;
265→
266→    ALFPTacticsPlayerController* PC = GetWorld()->GetFirstPlayerController<ALFPTacticsPlayerController>();
267→
268→    // 敌方单位在行动阶段：执行预定计划
269→    if (Unit->IsEnemy() && CurrentPhase == EBattlePhase::BP_ActionPhase)
270→    {
271→        if (PC)
272→        {
273→            PC->HideSkillSelection();
274→        }
275→
276→        Unit->OnTurnStarted();
277→
278→        ExecuteEnemyPlan(Unit);
279→        return;
280→    }
281→
282→    // 玩家单位：保持原有逻辑
283→    if (Unit)
284→    {
285→        Unit->OnTurnStarted();
286→    }
287→
288→    if (PC)
289→    {
290→        PC->OnTurnStarted(Unit);
291→        PC->SelectUnit(Unit);
292→        PC->HandleSkillSelection();
293→    }
294→}
295→
296→void ALFPTurnManager::ExecuteEnemyPlan(ALFPTacticsUnit* Unit)
297→{
298→    const FEnemyActionPlan& Plan = GetPlanForEnemy(Unit);
299→
300→    if (Plan.bIsValid && Plan.PlannedSkill)
301→    {
302→        // 在原定目标格子释放技能（即使目标已死亡）
303→        // AP 已在规划阶段 AllocateEnemySkills 中扣除
304→        Unit->ExecuteSkill(Plan.PlannedSkill, Plan.TargetTile);
305→    }
306→
307→    // 清除头顶技能图标
308→    Unit->ClearActionPlan();
309→
310→    // 短延时后结束回合（让玩家看到技能效果）
311→    FTimerHandle TimerHandle;
312→    GetWorld()->GetTimerManager().SetTimer(TimerHandle, [this, Unit]()
313→    {
314→        Unit->SetHasActed(true);
315→        PassTurn();
316→    }, 0.5f, false);
317→}
318→
319→void ALFPTurnManager::EndUnitTurn(ALFPTacticsUnit* Unit)
320→{
321→    if (Unit)
322→    {
323→        Unit->OnTurnEnded();
324→    }
325→
326→    // 通知玩家控制器
327→    if (ALFPTacticsPlayerController* PC = GetWorld()->GetFirstPlayerController<ALFPTacticsPlayerController>())
328→    {
329→        PC->OnTurnEnded(Unit);
330→    }
331→}
332→
333→void ALFPTurnManager::PassTurn()
334→{
335→    if (!CurrentUnit || TurnOrderUnits.IsEmpty())
336→    {
337→        return;
338→    }
339→
340→    // 结束当前单位回合
341→    EndUnitTurn(CurrentUnit);
342→
343→    // 找到下一个未行动的单位
344→    int32 CurrentIndex = TurnOrderUnits.Find(CurrentUnit);
345→    int32 NextIndex = (CurrentIndex + 1) % TurnOrderUnits.Num();
346→
347→    // 检查所有单位是否行动完毕
348→    bool TurnOrderUnitsActed = true;
349→    for (ALFPTacticsUnit* Unit : TurnOrderUnits)
350→    {
351→        if (Unit && Unit->IsAlive() && !Unit->HasActed())
352→        {
353→            TurnOrderUnitsActed = false;
354→            break;
355→        }
356→    }
357→
358→    if (TurnOrderUnitsActed)
359→    {
360→        // 所有单位行动完毕，结束回合
361→        EndCurrentRound();
362→    }
363→    else
364→    {
365→        // 寻找下一个未行动单位
366→        for (int32 i = 0; i < TurnOrderUnits.Num(); i++)
367→        {
368→            int32 Index = (NextIndex + i) % TurnOrderUnits.Num();
369→            ALFPTacticsUnit* NextUnit = TurnOrderUnits[Index];
370→
371→            if (NextUnit && NextUnit->IsAlive() && !NextUnit->HasActed())
372→            {
373→                BeginUnitTurn(NextUnit);
374→                return;
375→            }
376→        }
377→
378→        // 没有找到未行动单位，结束回合
379→        EndCurrentRound();
380→    }
381→}
382→
383→void ALFPTurnManager::OnUnitFinishedAction(ALFPTacticsUnit* Unit)
384→{
385→    if (Unit == CurrentUnit)
386→    {
387→        Unit->SetHasActed(true);
388→
389→        // 自动传递回合
390→        PassTurn();
391→    }
392→}
393→
394→void ALFPTurnManager::RegisterUnit(ALFPTacticsUnit* Unit)
395→{
396→    if (Unit && !TurnOrderUnits.Contains(Unit))
397→    {
398→        TurnOrderUnits.Add(Unit);
399→
400→        // 如果游戏已经开始，重新排序
401→        if (bIsInRound)
402→        {
403→            SortUnitsBySpeed();
404→        }
405→    }
406→}
407→
408→void ALFPTurnManager::UnregisterUnit(ALFPTacticsUnit* Unit)
409→{
410→    if (Unit)
411→    {
412→        TurnOrderUnits.Remove(Unit);
413→
414→        // 如果当前单位被移除，传递回合
415→        if (Unit == CurrentUnit)
416→        {
417→            PassTurn();
418→        }
419→    }
420→}
421→
422→const FEnemyActionPlan& ALFPTurnManager::GetPlanForEnemy(ALFPTacticsUnit* Enemy) const
423→{
424→    for (const FEnemyActionPlan& Plan : EnemyActionPlans)
425→    {
426→        if (Plan.EnemyUnit == Enemy)
427→        {
428→            return Plan;
429→        }
430→    }
431→    return EmptyPlan;
432→}
433→
434→// ==== 阵营行动点 ====
435→
436→int32 ALFPTurnManager::GetFactionAP(EUnitAffiliation Faction) const
437→{
438→    const int32* AP = FactionCurrentAP.Find(Faction);
439→    return AP ? *AP : 0;
440→}
441→
442→bool ALFPTurnManager::HasEnoughFactionAP(EUnitAffiliation Faction, int32 Amount) const
443→{
444→    return GetFactionAP(Faction) >= Amount;
445→}
446→
447→void ALFPTurnManager::ConsumeFactionAP(EUnitAffiliation Faction, int32 Amount)
448→{
449→    if (int32* AP = FactionCurrentAP.Find(Faction))
450→    {
451→        *AP = FMath::Max(0, *AP - Amount);
452→        OnFactionAPChanged.Broadcast(Faction, *AP);
453→    }
454→}
455→
456→// ==== 全局技能分配 ====
457→
458→void ALFPTurnManager::AllocateEnemySkills()
459→{
460→    AllocatedSkills.Empty();
461→
462→    // 收集所有敌方单位的所有消耗AP的技能候选
463→    struct FSkillCandidate
464→    {
465→        ALFPTacticsUnit* Unit;
466→        ULFPSkillBase* Skill;
467→        float EffectivePriority;
468→    };
469→    TArray<FSkillCandidate> Candidates;
470→
471→    for (ALFPTacticsUnit* Enemy : PlanningOrderEnemies)
472→    {
473→        if (!Enemy || !Enemy->IsAlive()) continue;
474→
475→        TArray<ULFPSkillBase*> Skills = Enemy->GetAvailableSkills();
476→        for (ULFPSkillBase* Skill : Skills)
477→        {
478→            if (!Skill) continue;
479→            if (Skill->ActionPointCost <= 0) continue; // 0消耗技能不参与竞争
480→            if (Skill->CurrentCooldown > 0) continue;  // 冷却中跳过
481→
482→            FSkillCandidate Candidate;
483→            Candidate.Unit = Enemy;
484→            Candidate.Skill = Skill;
485→            Candidate.EffectivePriority = Skill->GetEffectivePriority();
486→            Candidates.Add(Candidate);
487→        }
488→    }
489→
490→    // 按有效优先级降序排序
491→    Candidates.Sort([](const FSkillCandidate& A, const FSkillCandidate& B) {
492→        return A.EffectivePriority > B.EffectivePriority;
493→    });
494→
495→    // 依次分配：如果阵营AP足够且该单位尚未分配
496→    for (const FSkillCandidate& Candidate : Candidates)
497→    {
498→        // 该单位已分配过技能，跳过
499→        if (AllocatedSkills.Contains(Candidate.Unit)) continue;
500→
501→        // 检查阵营AP是否足够
502→        if (HasEnoughFactionAP(EUnitAffiliation::UA_Enemy, Candidate.Skill->ActionPointCost))
503→        {
504→            AllocatedSkills.Add(Candidate.Unit, Candidate.Skill);
505→            ConsumeFactionAP(EUnitAffiliation::UA_Enemy, Candidate.Skill->ActionPointCost);
506→        }
507→    }
508→
509→    // 未分配到AP技能的敌人会在 CreateActionPlan 中 fallback 到默认攻击
510→}
511→

