        Pair.Value = FMath::Min(Pair.Value + FactionAPRecovery, FactionMaxAP);
        OnFactionAPChanged.Broadcast(Pair.Key, Pair.Value);
    }

    // 进入敌人规划阶段
    BeginEnemyPlanningPhase();
