        TurnOrderUnits.Remove(Unit);

        // 先检查战斗结束条件
        CheckBattleEnd();

        // 如果战斗未结束且当前单位被移除，传递回合
        if (!bBattleEnded && bWasCurrentUnit)
        {
            PassTurn();
        }
    }
}

